function notificationReducer(state = { notifications: [] }, action) {
  let newState;
  const userId = state.auth?.user?.id;

  switch (action.type) {
    case "ADD_NOTIFICATION":
      newState = {
        ...state,
        notifications: [...state.notifications, action.payload],
      };
      if (userId) {
        localStorage.setItem(`notifications_${userId}`, JSON.stringify(newState.notifications));
      }
      return newState;
    case "REMOVE_NOTIFICATION":
      newState = {
        ...state,
        notifications: state.notifications.filter((n) => n.id !== action.payload),
      };
      if (userId) {
        localStorage.setItem(`notifications_${userId}`, JSON.stringify(newState.notifications));
      }
      return newState;
    default:
      if (userId) {
        const storedNotifications = JSON.parse(localStorage.getItem(`notifications_${userId}`)) || [];
        return { ...state, notifications: storedNotifications };
      }
      return state;
  }
}

export default notificationReducer;

export const addNotification = (notification) => ({
  type: "ADD_NOTIFICATION",
  payload: notification,
});

export const removeNotification = (id) => ({
  type: "REMOVE_NOTIFICATION",
  payload: id,
});
